const BUSINESS_DATA = {
  pharmacy,
  restaurant,
  gas_station,
  grocery,
  b2b_wholesale,
  distributor,
  general_retail,
};

export function getBusinessDefaults(businessType) {
  const data = BUSINESS_DATA[businessType];
  if (!data) return null;
  return {
    products: data.products,
    suppliers: data.suppliers,
    customers: data.customers,
    orders: data.orders,
    notifications: data.notifications,
    stockMovements: data.stockMovements,
    salesOrders: data.salesOrders || [],
  };
}
